(function(){function elemFromEvent(ev){var t=ev.target;if(!t)return null;return t.nodeType===1?t:t.parentElement;}
function loadJobs(){var jobs=[];var el=document.getElementById("career-recruitment-json");if(el&&el.textContent){try{jobs=JSON.parse(el.textContent.trim());}catch(e){jobs=[];}}
if(!Array.isArray(jobs)&&typeof window.__RECRUITMENT_JOBS__!=="undefined"){jobs=window.__RECRUITMENT_JOBS__;}
return Array.isArray(jobs)?jobs:[];}
var jobs=loadJobs();function escapeHtml(s){if(s==null||s==="")return"";var d=document.createElement("div");d.textContent=String(s);return d.innerHTML;}
function listItems(arr){if(!arr||!arr.length)return"";return arr.map(function(line){return"<li>"+escapeHtml(line)+"</li>";}).join("");}
function findJob(slug){for(var i=0;i<jobs.length;i++){if(jobs[i].slug===slug)return jobs[i];}
return null;}
function noop(){}
window.openCareerModal=noop;window.closeCareerModal=noop;function initCareerModal(){var root=document.getElementById("career-modal-root");var contentEl=document.getElementById("career-modal-content");if(!root||!contentEl){return;}
var lastActive=null;function setOpen(open){if(open){root.removeAttribute("hidden");root.classList.add("is-open");root.setAttribute("aria-hidden","false");document.body.classList.add("career-modal-open");lastActive=document.activeElement;var closeBtn=root.querySelector(".career-modal-close");if(closeBtn)closeBtn.focus();}else{root.classList.remove("is-open");root.setAttribute("aria-hidden","true");document.body.classList.remove("career-modal-open");window.setTimeout(function(){root.setAttribute("hidden","");},280);if(lastActive&&typeof lastActive.focus==="function"){try{lastActive.focus();}catch(e){}}}}
function bindForm(){var form=contentEl.querySelector(".career-apply-form");if(!form)return;var fileInput=form.querySelector('input[name="cv"]');var nameOut=form.querySelector("[data-cv-filename]");if(fileInput&&nameOut){fileInput.addEventListener("change",function(){var f=fileInput.files&&fileInput.files[0];nameOut.textContent=f?f.name:"";});}
form.addEventListener("submit",function(ev){ev.preventDefault();var submitBtn=form.querySelector(".career-submit-btn");var msgEl=form.querySelector(".career-modal-form-msg");if(msgEl){msgEl.textContent="";msgEl.className="career-modal-form-msg";}
var fd=new FormData(form);if(submitBtn){submitBtn.disabled=true;submitBtn.dataset.label=submitBtn.textContent;submitBtn.textContent="Đang gửi…";}
fetch(form.action,{method:"POST",body:fd,headers:{"X-Requested-With":"XMLHttpRequest"},credentials:"same-origin",}).then(function(res){var ct=res.headers.get("content-type")||"";if(ct.indexOf("application/json")!==-1){return res.json().then(function(data){return{ok:res.ok,status:res.status,data:data};});}
if(res.status===413){return{ok:false,status:res.status,data:{ok:false,error:"Tệp CV quá lớn (tối đa 5MB)."},};}
return{ok:false,status:res.status,data:{ok:false,error:"Máy chủ trả lời không hợp lệ."},};}).then(function(result){if(result.ok&&result.data&&result.data.ok){if(msgEl){msgEl.textContent=result.data.message||"Đã gửi thành công.";msgEl.classList.add("is-success");}
form.reset();if(nameOut)nameOut.textContent="";contentEl.scrollTop=0;}else{var err=(result.data&&result.data.error)||(result.status===413?"Tệp CV quá lớn (tối đa 5MB).":"Không gửi được. Vui lòng thử lại.");if(msgEl){msgEl.textContent=err;msgEl.classList.add("is-error");}}}).catch(function(){if(msgEl){msgEl.textContent="Lỗi mạng. Vui lòng thử lại.";msgEl.classList.add("is-error");}}).finally(function(){if(submitBtn){submitBtn.disabled=false;submitBtn.textContent=submitBtn.dataset.label||"Ứng tuyển";}});});}
function renderJob(job){var applyUrl="/career/"+encodeURIComponent(job.slug)+"/apply";return('<article class="career-modal-article">'+'<header class="career-modal-intro">'+'<p class="career-eyebrow">Vị trí tuyển dụng</p>'+'<h2 id="career-modal-title" class="career-modal-title">'+
escapeHtml(job.title)+"</h2>"+'<div class="career-detail-meta">'+'<span class="recruitment-pill">'+
escapeHtml(job.location)+"</span>"+'<span class="recruitment-pill recruitment-pill-muted">'+
escapeHtml(job.employment_type)+"</span>"+"</div>"+"</header>"+'<p class="career-detail-intro">'+
escapeHtml(job.intro)+"</p>"+'<section class="career-detail-block">'+"<h3>Trách nhiệm chính</h3>"+"<ul class=\"career-detail-list\">"+
listItems(job.responsibilities)+"</ul>"+"</section>"+'<section class="career-detail-block">'+"<h3>Yêu cầu</h3>"+"<ul class=\"career-detail-list\">"+
listItems(job.requirements)+"</ul>"+"</section>"+'<section class="career-detail-block">'+"<h3>Phúc lợi</h3>"+"<ul class=\"career-detail-list\">"+
listItems(job.benefits)+"</ul>"+"</section>"+'<section class="career-detail-cta career-modal-form-wrap">'+"<h3>Ứng tuyển</h3>"+'<p class="career-apply-lead">Điền thông tin và đính kèm CV. Chúng tôi sẽ phản hồi sớm nhất có thể.</p>'+'<p class="career-modal-form-msg" role="status"></p>'+'<form class="career-apply-form" method="post" action="'+
applyUrl+'" enctype="multipart/form-data" novalidate>'+'<div class="career-form-row">'+'<label for="career-m-full-name">Họ và tên <span class="career-req">*</span></label>'+'<input type="text" id="career-m-full-name" name="full_name" autocomplete="name" required placeholder="Nguyễn Văn A" />'+"</div>"+'<div class="career-form-row career-form-row-split">'+"<div>"+'<label for="career-m-email">Email <span class="career-req">*</span></label>'+'<input type="email" id="career-m-email" name="email" autocomplete="email" required placeholder="ten@email.com" />'+"</div>"+"<div>"+'<label for="career-m-phone">Số điện thoại <span class="career-req">*</span></label>'+'<input type="tel" id="career-m-phone" name="phone" autocomplete="tel" required placeholder="09xx xxx xxx" />'+"</div>"+"</div>"+'<div class="career-form-row">'+'<label for="career-m-cover">Giới thiệu ngắn / Thư xin việc</label>'+'<textarea id="career-m-cover" name="cover_letter" rows="4" placeholder="Vài dòng về kinh nghiệm (không bắt buộc)"></textarea>'+"</div>"+'<div class="career-form-row career-file-row">'+'<span class="career-file-label">CV đính kèm <span class="career-req">*</span></span>'+'<div class="career-file-controls">'+'<input type="file" id="career-m-cv" name="cv" required class="career-file-input" accept=".pdf,.doc,.docx,application/pdf" />'+'<label for="career-m-cv" class="btn career-file-btn">Chọn tệp CV</label>'+'<span class="career-file-name" data-cv-filename aria-live="polite"></span>'+"</div>"+'<p class="career-file-hint">PDF, DOC hoặc DOCX — tối đa 5MB.</p>'+"</div>"+'<div class="career-form-actions">'+'<button type="submit" class="btn career-submit-btn">Ứng tuyển</button>'+"</div>"+"</form>"+"</section>"+"</article>");}
window.openCareerModal=function(slug){var job=findJob(slug);if(!job)return;contentEl.innerHTML=renderJob(job);bindForm();setOpen(true);};window.closeCareerModal=function(){setOpen(false);};root.addEventListener("click",function(ev){var el=elemFromEvent(ev);var closer=el&&el.closest?el.closest("[data-career-modal-close]"):null;if(closer){ev.preventDefault();window.closeCareerModal();}});document.addEventListener("keydown",function(ev){if(ev.key==="Escape"&&root.classList.contains("is-open")){window.closeCareerModal();}});document.addEventListener("click",function(ev){var el=elemFromEvent(ev);var btn=el&&el.closest?el.closest("[data-career-open]"):null;if(!btn)return;ev.preventDefault();var slug=btn.getAttribute("data-career-open");if(slug)window.openCareerModal(slug);});function openFromQuery(){try{var q=new URLSearchParams(window.location.search).get("job");if(q){window.openCareerModal(q);if(window.history&&window.history.replaceState){window.history.replaceState({},"",window.location.pathname);}}}catch(e){}}
openFromQuery();}
function boot(){initCareerModal();}
if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",boot);}else{boot();}})();